SELECT grape_name
FROM grapes
WHERE grape_id = 1;

SELECT DISTINCT wine_id
FROM tasting_events
WHERE event_type = 'Private';

SELECT origin_name
FROM origins
WHERE country = 'Australia';

SELECT MAX(rating) AS highest_rating
FROM wine_reviews
WHERE wine_id = 0;

SELECT participants
FROM tasting_events
WHERE event_id = 1;
